1130→// which will also delete the blocks that fall out of the retention window.
  1131→// Old blocks are only deleted on reloadBlocks based on the new block's parent information.
  1132→// See DB.reloadBlocks documentation for further information.
  1133→func (db *DB) Compact(ctx context.Context) (returnErr error) {
  1134→	db.cmtx.Lock()
  1135→	defer db.cmtx.Unlock()
  1136→	defer func() {
  1137→		if returnErr != nil && !errors.Is(returnErr, context.Canceled) {
  1138→			// If we got an error because context was canceled then we're most likely
  1139→			// shutting down TSDB and we don't need to report this on metrics
  1140→			db.metrics.compactionsFailed.Inc()
  1141→		}
  1142→	}()
  1143→
  1144→	lastBlockMaxt := int64(math.MinInt64)
  1145→	defer func() {
  1146→		errs := tsdb_errors.NewMulti(returnErr)
  1147→		if err := db.head.truncateWAL(lastBlockMaxt); err != nil {
  1148→			errs.Add(fmt.Errorf("WAL truncation in Compact defer: %w", err))
  1149→		}
  1150→		returnErr = errs.Err()
  1151→	}()
  1152→
  1153→	start := time.Now()
  1154→	// Check whether we have pending head blocks that are ready to be persisted.
  1155→	// They have the highest priority.
  1156→	for {
  1157→		select {
  1158→		case <-db.stopc:
  1159→			return nil
  1160→		default:
  1161→		}
  1162→		if !db.head.compactable() {
  1163→			break
  1164→		}
  1165→		mint := db.head.MinTime()
  1166→		maxt := rangeForTimestamp(mint, db.head.chunkRange.Load())
  1167→
  1168→		// Wrap head into a range that bounds all reads to it.
  1169→		// We remove 1 millisecond from maxt because block
  1170→		// intervals are half-open: [b.MinTime, b.MaxTime). But
  1171→		// chunk intervals are closed: [c.MinTime, c.MaxTime];
  1172→		// so in order to make sure that overlaps are evaluated
  1173→		// consistently, we explicitly remove the last value
  1174→		// from the block interval here.
  1175→		rh := NewRangeHeadWithIsolationDisabled(db.head, mint, maxt-1)
  1176→
  1177→		// Compaction runs with isolation disabled, because head.compactable()
  1178→		// ensures that maxt is more than chunkRange/2 back from now, and
  1179→		// head.appendableMinValidTime() ensures that no new appends can start within the compaction range.
  1180→		// We do need to wait for any overlapping appenders that started previously to finish.
  1181→		db.head.WaitForAppendersOverlapping(rh.MaxTime())
  1182→
  1183→		if err := db.compactHead(rh); err != nil {
  1184→			return fmt.Errorf("compact head: %w", err)
  1185→		}
  1186→		// Consider only successful compactions for WAL truncation.
  1187→		lastBlockMaxt = maxt
  1188→	}
  1189→
  1190→	// Clear some disk space before compacting blocks, especially important
  1191→	// when Head compaction happened over a long time range.
  1192→	if err := db.head.truncateWAL(lastBlockMaxt); err != nil {
  1193→		return fmt.Errorf("WAL truncation in Compact: %w", err)
  1194→	}
  1195→
  1196→	compactionDuration := time.Since(start)
  1197→	if compactionDuration.Milliseconds() > db.head.chunkRange.Load() {
  1198→		level.Warn(db.logger).Log(
  1199→			"msg", "Head compaction took longer than the block time range, compactions are falling behind and won't be able to catch up",
  1200→			"duration", compactionDuration.String(),
  1201→			"block_range", db.head.chunkRange.Load(),
  1202→		)
  1203→	}
  1204→
  1205→	if lastBlockMaxt != math.MinInt64 {
  1206→		// The head was compacted, so we compact OOO head as well.
  1207→		if err := db.compactOOOHead(ctx); err != nil {
  1208→			return fmt.Errorf("compact ooo head: %w", err)
  1209→		}
  1210→	}
  1211→
  1212→	return db.compactBlocks()
  1213→}
