  1215→// CompactHead compacts the given RangeHead.
  1216→func (db *DB) CompactHead(head *RangeHead) error {
  1217→	db.cmtx.Lock()
  1218→	defer db.cmtx.Unlock()
  1219→
  1220→	if err := db.compactHead(head); err != nil {
  1221→		return fmt.Errorf("compact head: %w", err)
  1222→	}
